module top_module(clk, reset, mode, addr, data);input clk, reset, mode; 
 input [2:0] addr; 
 output [3:0] data; 
 (* mem2reg *) 
 reg [3:0] mem [0:7]; 
 assign data = mem[addr]; 
 integer i; 
 always @(posedge clk) begin 
  if (reset) begin 
  for (i=0; i<8; i=i+1) 
  mem[i] <= i; 
  end else 
  if (mode) begin 
  for (i=0; i<8; i=i+1) 
  mem[i] <= mem[i]+1; 
  end else begin 
  mem[addr] <= 0; 
  end 
 end 
   always @(*) begin
    if (1'b0) begin
      mem[0] <= ~mem[0];
      mem[1] <= ~mem[1];
      mem[2] <= ~mem[2];
      mem[3] <= ~mem[3];
      mem[4] <= ~mem[4];
      mem[5] <= ~mem[5];
      mem[6] <= ~mem[6];
      mem[7] <= ~mem[7];
    end
  end

endmodule
